from distutils.command.install import valuefrom attr.validators import max_lenfrom pydantic import BaseModel, EmailStr, field_validator  # email str use to validate the email we are using in our production based code #this module helps us to import the correct url in the systemfrom pydantic import Field,AnyUrlfrom typing import List,Dict,Optional,Annotatedclass Student(BaseModel):    #defining the ideal schema in the class    #name:str this is one way of accepting your data in the field    name:Annotated[str,Field(max_length=50,title='name of the student',description='give the name of the student in less than 50 characters')]    age:int = Field(gt=18,lt=22) #using this we can define the range of the input in our system we are taking    branch:str= Field(max_length = 4)    email:EmailStr    year:int    skills:List[str]    contact_details:Optional[Dict[str,str]]    @field_validator('email')    @classmethod    def email_validator(cls,value):        valid_domain = ['@gmail.com','@outlook.com']        domain_name = value.split('a')[-1]        if domain_name not in valid_domain:            raise ValueError('not a valid input for the domain')        raise value    @field_validator('name')    @classmethod    def uppercase(cls,value):        return value.upper()    @field_validator('age',mode='before')    @classmethod    def validate_age(cls,value):        if 0<value<30:            return value        else:            raise ValueError('the entered age is not correct')        return valuedef insert_student_data(student:Student):    print(student.name)    print(student.age)    print(student.branch)    print(student.year)    print(student.skills)    print(F'we have inserted the detals of the {Student.name} in our data')#creating a dictionary in the pydantic formatstudent_info = {'name':'raghav','age':22,'email':'raghavnmh66@gmail.com'                ,'branch':'bmie','year':2027,'skills':['ai/ml'],'contact_details': {    'email': 'raghavnmh66@gmail.com',    'phone_number': '8000847999'}}student1 = Student(**student_info) # this syntax is known as unpacking the dictionaryinsert_student_data(student1)